use crate::types::{DecideInput, DecideOutput};

// Compare two real numbers with respect to six most significant digits.
// Returns "LT", "EQ", or "GT".
fn realcompare(a: f64, b: f64) -> &'static str {
    // Scale both values to 6 significant digits by rounding to 6 sig figs.
    // We compare by examining whether the difference is within the precision
    // of 6 significant digits of the larger magnitude.
    let scale = if a == 0.0 && b == 0.0 {
        1.0
    } else {
        let max_abs = a.abs().max(b.abs());
        // 10^(floor(log10(max_abs)) - 5) gives the unit of the 6th sig digit
        let exp = max_abs.log10().floor() - 5.0;
        10_f64.powf(exp)
    };

    // Round both to 6 sig figs
    let ra = (a / scale).round() * scale;
    let rb = (b / scale).round() * scale;

    if ra < rb {
        "LT"
    } else if ra > rb {
        "GT"
    } else {
        "EQ"
    }
}

// Euclidean distance between two points
fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

// Area of a triangle given three points (using cross product / 2)
fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0).abs()
}

// Circumradius of three points.
// Returns f64::INFINITY if points are collinear.
fn circumradius(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    let a = dist(x1, y1, x2, y2);
    let b = dist(x2, y2, x3, y3);
    let c = dist(x1, y1, x3, y3);
    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if area == 0.0 {
        // Collinear: circumradius is half the longest segment
        let max_side = a.max(b).max(c);
        max_side / 2.0
    } else {
        (a * b * c) / (4.0 * area)
    }
}

// Determine which quadrant a point belongs to (priority: I > II > III > IV)
// Quadrant I:  x >= 0 and y >= 0
// Quadrant II: x < 0  and y >= 0
// Quadrant III:x <= 0 and y < 0
// Quadrant IV: x > 0  and y < 0
fn quadrant(x: f64, y: f64) -> u8 {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        // x > 0 and y < 0
        4
    }
}

// Distance from point (px,py) to the line through (x1,y1)-(x2,y2).
// If the two line endpoints are identical, returns distance between the point and that endpoint.
fn point_to_line_dist(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    let len_sq = dx * dx + dy * dy;
    if len_sq == 0.0 {
        // Coincident endpoints: distance to the point
        dist(px, py, x1, y1)
    } else {
        // |cross product| / |segment length|
        ((dy * px - dx * py + x2 * y1 - y2 * x1).abs()) / len_sq.sqrt()
    }
}

// -------------------------------------------------------------------------
// LIC implementations (0-based indices internally; spec uses 1-based)
// -------------------------------------------------------------------------

/// LIC 1: exists consecutive pair distance > LENGTH1
fn lic1(input: &DecideInput) -> bool {
    let l1 = input.parameters.length1;
    for i in 0..input.numpoints - 1 {
        let d = dist(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
        if realcompare(d, l1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 2: exists consecutive triple that cannot all be contained in circle of radius RADIUS1
fn lic2(input: &DecideInput) -> bool {
    let r1 = input.parameters.radius1;
    for i in 0..input.numpoints - 2 {
        let r = circumradius(
            input.x[i], input.y[i],
            input.x[i + 1], input.y[i + 1],
            input.x[i + 2], input.y[i + 2],
        );
        if realcompare(r, r1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 3: exists consecutive triple forming angle < PI - EPSILON or > PI + EPSILON
/// Vertex is the second point. If first or last coincides with vertex, undefined (skip).
fn lic3(input: &DecideInput) -> bool {
    let eps = input.parameters.epsilon;
    let pi = std::f64::consts::PI;
    for i in 0..input.numpoints - 2 {
        let (ax, ay) = (input.x[i], input.y[i]);
        let (bx, by) = (input.x[i + 1], input.y[i + 1]);
        let (cx, cy) = (input.x[i + 2], input.y[i + 2]);
        // Check if first or last coincides with vertex
        if (ax == bx && ay == by) || (cx == bx && cy == by) {
            continue;
        }
        // Vector from B to A, and from B to C
        let v1x = ax - bx;
        let v1y = ay - by;
        let v2x = cx - bx;
        let v2y = cy - by;
        let dot = v1x * v2x + v1y * v2y;
        let mag1 = (v1x * v1x + v1y * v1y).sqrt();
        let mag2 = (v2x * v2x + v2y * v2y).sqrt();
        let cos_angle = (dot / (mag1 * mag2)).clamp(-1.0, 1.0);
        let angle = cos_angle.acos();
        if realcompare(angle, pi - eps) == "LT" || realcompare(angle, pi + eps) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 4: exists consecutive triple forming triangle with area > AREA1
fn lic4(input: &DecideInput) -> bool {
    let a1 = input.parameters.area1;
    for i in 0..input.numpoints - 2 {
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[i + 1], input.y[i + 1],
            input.x[i + 2], input.y[i + 2],
        );
        if realcompare(area, a1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 5: exists Q_PTS consecutive points in more than QUADS quadrants
fn lic5(input: &DecideInput) -> bool {
    let q_pts = input.parameters.q_pts;
    let quads = input.parameters.quads;
    if q_pts > input.numpoints {
        return false;
    }
    for i in 0..=(input.numpoints - q_pts) {
        let mut seen = [false; 5]; // indices 1..4
        for j in i..i + q_pts {
            let q = quadrant(input.x[j], input.y[j]) as usize;
            seen[q] = true;
        }
        let count = seen[1..5].iter().filter(|&&v| v).count();
        if count > quads {
            return true;
        }
    }
    false
}

/// LIC 6: exists consecutive pair where X[j] - X[i] < 0, j = i+1
fn lic6(input: &DecideInput) -> bool {
    for i in 0..input.numpoints - 1 {
        if realcompare(input.x[i + 1] - input.x[i], 0.0) == "LT" {
            return true;
        }
    }
    false
}

/// LIC 7: exists N_PTS consecutive points where at least one is distance > DIST from
/// the line joining first and last of those N_PTS points.
/// Condition not met when NUMPOINTS < 3.
fn lic7(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let n_pts = input.parameters.n_pts;
    let d_param = input.parameters.dist;
    if n_pts > input.numpoints {
        return false;
    }
    for i in 0..=(input.numpoints - n_pts) {
        let fx = input.x[i];
        let fy = input.y[i];
        let lx = input.x[i + n_pts - 1];
        let ly = input.y[i + n_pts - 1];
        // Check all intermediate points
        for j in i + 1..i + n_pts - 1 {
            let d = point_to_line_dist(input.x[j], input.y[j], fx, fy, lx, ly);
            if realcompare(d, d_param) == "GT" {
                return true;
            }
        }
    }
    false
}

/// LIC 8: exists pair separated by K_PTS consecutive intervening points with distance > LENGTH1.
/// Condition not met when NUMPOINTS < 3.
fn lic8(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let k_pts = input.parameters.k_pts;
    let l1 = input.parameters.length1;
    // i and j = i + k_pts + 1
    let step = k_pts + 1;
    if step >= input.numpoints {
        return false;
    }
    for i in 0..=(input.numpoints - 1 - step) {
        let j = i + step;
        let d = dist(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, l1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 9: exists triple separated by A_PTS and B_PTS that cannot be contained in circle of RADIUS1.
/// Condition not met when NUMPOINTS < 5.
fn lic9(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let r1 = input.parameters.radius1;
    // Indices: i, i + a_pts + 1, i + a_pts + 1 + b_pts + 1
    let gap1 = a_pts + 1;
    let gap2 = b_pts + 1;
    let last_i = input.numpoints.saturating_sub(gap1 + gap2 + 1);
    for i in 0..=last_i {
        let j = i + gap1;
        let k = j + gap2;
        if k >= input.numpoints {
            break;
        }
        let r = circumradius(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
        );
        if realcompare(r, r1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 10: exists triple separated by C_PTS and D_PTS forming angle < PI-EPSILON or > PI+EPSILON.
/// Condition not met when NUMPOINTS < 5.
fn lic10(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let c_pts = input.parameters.c_pts;
    let d_pts = input.parameters.d_pts;
    let eps = input.parameters.epsilon;
    let pi = std::f64::consts::PI;
    let gap1 = c_pts + 1;
    let gap2 = d_pts + 1;
    let last_i = input.numpoints.saturating_sub(gap1 + gap2 + 1);
    for i in 0..=last_i {
        let j = i + gap1;
        let k = j + gap2;
        if k >= input.numpoints {
            break;
        }
        let (ax, ay) = (input.x[i], input.y[i]);
        let (bx, by) = (input.x[j], input.y[j]);
        let (cx, cy) = (input.x[k], input.y[k]);
        // Vertex is the second point (j)
        if (ax == bx && ay == by) || (cx == bx && cy == by) {
            continue;
        }
        let v1x = ax - bx;
        let v1y = ay - by;
        let v2x = cx - bx;
        let v2y = cy - by;
        let dot = v1x * v2x + v1y * v2y;
        let mag1 = (v1x * v1x + v1y * v1y).sqrt();
        let mag2 = (v2x * v2x + v2y * v2y).sqrt();
        let cos_angle = (dot / (mag1 * mag2)).clamp(-1.0, 1.0);
        let angle = cos_angle.acos();
        if realcompare(angle, pi - eps) == "LT" || realcompare(angle, pi + eps) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 11: exists triple separated by E_PTS and F_PTS forming triangle with area > AREA1.
/// Condition not met when NUMPOINTS < 5.
fn lic11(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let a1 = input.parameters.area1;
    let gap1 = e_pts + 1;
    let gap2 = f_pts + 1;
    let last_i = input.numpoints.saturating_sub(gap1 + gap2 + 1);
    for i in 0..=last_i {
        let j = i + gap1;
        let k = j + gap2;
        if k >= input.numpoints {
            break;
        }
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
        );
        if realcompare(area, a1) == "GT" {
            return true;
        }
    }
    false
}

/// LIC 12: exists pair separated by G_PTS where X[j] - X[i] < 0 (i < j).
/// Condition not met when NUMPOINTS < 3.
fn lic12(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let g_pts = input.parameters.g_pts;
    let step = g_pts + 1;
    if step >= input.numpoints {
        return false;
    }
    for i in 0..=(input.numpoints - 1 - step) {
        let j = i + step;
        if realcompare(input.x[j] - input.x[i], 0.0) == "LT" {
            return true;
        }
    }
    false
}

/// LIC 13: two conditions both met:
///   (a) exists pair separated by K_PTS with distance > LENGTH1
///   (b) exists pair separated by K_PTS with distance < LENGTH2
/// Condition not met when NUMPOINTS < 3.
fn lic13(input: &DecideInput) -> bool {
    if input.numpoints < 3 {
        return false;
    }
    let k_pts = input.parameters.k_pts;
    let l1 = input.parameters.length1;
    let l2 = input.parameters.length2;
    let step = k_pts + 1;
    if step >= input.numpoints {
        return false;
    }
    let mut part_a = false;
    let mut part_b = false;
    for i in 0..=(input.numpoints - 1 - step) {
        let j = i + step;
        let d = dist(input.x[i], input.y[i], input.x[j], input.y[j]);
        if realcompare(d, l1) == "GT" {
            part_a = true;
        }
        if realcompare(d, l2) == "LT" {
            part_b = true;
        }
    }
    part_a && part_b
}

/// LIC 14: two conditions both met:
///   (a) exists triple (A_PTS, B_PTS gaps) not containable in circle of RADIUS1
///   (b) exists triple (A_PTS, B_PTS gaps) containable in circle of RADIUS2
/// Condition not met when NUMPOINTS < 5.
fn lic14(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let a_pts = input.parameters.a_pts;
    let b_pts = input.parameters.b_pts;
    let r1 = input.parameters.radius1;
    let r2 = input.parameters.radius2;
    let gap1 = a_pts + 1;
    let gap2 = b_pts + 1;
    let last_i = input.numpoints.saturating_sub(gap1 + gap2 + 1);
    let mut part_a = false;
    let mut part_b = false;
    for i in 0..=last_i {
        let j = i + gap1;
        let k = j + gap2;
        if k >= input.numpoints {
            break;
        }
        let r = circumradius(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
        );
        if realcompare(r, r1) == "GT" {
            part_a = true;
        }
        if realcompare(r, r2) != "GT" {
            // r <= r2
            part_b = true;
        }
    }
    part_a && part_b
}

/// LIC 15: two conditions both met:
///   (a) exists triple (E_PTS, F_PTS gaps) forming triangle with area > AREA1
///   (b) exists triple (E_PTS, F_PTS gaps) forming triangle with area < AREA2
/// Condition not met when NUMPOINTS < 5.
fn lic15(input: &DecideInput) -> bool {
    if input.numpoints < 5 {
        return false;
    }
    let e_pts = input.parameters.e_pts;
    let f_pts = input.parameters.f_pts;
    let a1 = input.parameters.area1;
    let a2 = input.parameters.area2;
    let gap1 = e_pts + 1;
    let gap2 = f_pts + 1;
    let last_i = input.numpoints.saturating_sub(gap1 + gap2 + 1);
    let mut part_a = false;
    let mut part_b = false;
    for i in 0..=last_i {
        let j = i + gap1;
        let k = j + gap2;
        if k >= input.numpoints {
            break;
        }
        let area = triangle_area(
            input.x[i], input.y[i],
            input.x[j], input.y[j],
            input.x[k], input.y[k],
        );
        if realcompare(area, a1) == "GT" {
            part_a = true;
        }
        if realcompare(area, a2) == "LT" {
            part_b = true;
        }
    }
    part_a && part_b
}

// -------------------------------------------------------------------------
// Main decide function
// -------------------------------------------------------------------------

pub fn decide(input: &DecideInput) -> DecideOutput {
    // Step 1: Compute CMV
    let cmv = vec![
        lic1(input),
        lic2(input),
        lic3(input),
        lic4(input),
        lic5(input),
        lic6(input),
        lic7(input),
        lic8(input),
        lic9(input),
        lic10(input),
        lic11(input),
        lic12(input),
        lic13(input),
        lic14(input),
        lic15(input),
    ];

    // Step 2: Compute PUM (15x15)
    // PUM[i][i] = input.pum_diag[i] (diagonal supplied by caller)
    // PUM[i][j] (i != j) depends on LCM[i][j]:
    //   NOTUSED -> true
    //   ANDD    -> cmv[i] && cmv[j]
    //   ORR     -> cmv[i] || cmv[j]
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                let connector = &input.lcm[i][j];
                pum[i][j] = match connector.as_str() {
                    "NOTUSED" => true,
                    "ANDD" => cmv[i] && cmv[j],
                    "ORR" => cmv[i] || cmv[j],
                    _ => true, // treat unknown as NOTUSED
                };
            }
        }
    }

    // Step 3: Compute FUV
    // FUV[i] = true if PUM[i][i] is false, OR if all elements in PUM row i are true.
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&v| v);
        }
    }

    // Step 4: Launch decision — all FUV elements must be true
    let launch = fuv.iter().all(|&v| v);

    DecideOutput { cmv, pum, fuv, launch }
}
